import{_ as i,c as a,o as t,a1 as d}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"API: Referencia de comandos | Agent Skills","description":"Conoce la API de Agent Skills. Comandos de construcción, tipos TypeScript y niveles de impacto.","frontmatter":{"title":"API: Referencia de comandos | Agent Skills","sidebarTitle":"API Referencia","subtitle":"API y referencia de comandos","description":"Conoce la API de Agent Skills. Comandos de construcción, tipos TypeScript y niveles de impacto.","tags":["Referencia","API","Línea de comandos","Definiciones de tipos"],"prerequisite":[]},"headers":[],"relativePath":"es/vercel-labs/agent-skills/appendix/reference/index.md","filePath":"es/vercel-labs/agent-skills/appendix/reference/index.md"}'),o={name:"es/vercel-labs/agent-skills/appendix/reference/index.md"};function n(r,e,c,s,l,p){return t(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="api-y-referencia-de-comandos" tabindex="-1">API y referencia de comandos <a class="header-anchor" href="#api-y-referencia-de-comandos" aria-label="Permalink to &quot;API y referencia de comandos&quot;">​</a></h1><p>Esta página proporciona referencia completa de API y comandos de Agent Skills, incluyendo comandos de la cadena de herramientas de compilación, definiciones de tipos TypeScript, formatos de plantillas SKILL.md y valores de enumeración de niveles de impacto.</p><h2 id="definiciones-de-tipos-typescript" tabindex="-1">Definiciones de tipos TypeScript <a class="header-anchor" href="#definiciones-de-tipos-typescript" aria-label="Permalink to &quot;Definiciones de tipos TypeScript&quot;">​</a></h2><h3 id="impactlevel-nivel-de-impacto" tabindex="-1">ImpactLevel（Nivel de impacto） <a class="header-anchor" href="#impactlevel-nivel-de-impacto" aria-label="Permalink to &quot;ImpactLevel（Nivel de impacto）&quot;">​</a></h3><p>El nivel de impacto se usa para identificar el grado de impacto en rendimiento de la regla, hay 6 niveles:</p><table tabindex="0"><thead><tr><th>Valor</th><th>Descripción</th><th>Escenario de aplicación</th></tr></thead><tbody><tr><td><code>CRITICAL</code></td><td>Cuello de botella clave</td><td>Debe repararse, de lo contrario afecta seriamente la experiencia del usuario (como cascadas de solicitudes, tamaño de paquete no optimizado)</td></tr><tr><td><code>HIGH</code></td><td>Mejora importante</td><td>Mejora significativa del rendimiento (como caché del servidor, eliminación de props duplicados)</td></tr><tr><td><code>MEDIUM-HIGH</code></td><td>Prioridad media-alta</td><td>Mejora obvia del rendimiento (como optimización de obtención de datos)</td></tr><tr><td><code>MEDIUM</code></td><td>Mejora media</td><td>Mejora medible del rendimiento (como optimización de Memo, reducción de re-render)</td></tr><tr><td><code>LOW-MEDIUM</code></td><td>Prioridad media-baja</td><td>Mejora ligera del rendimiento (como optimización de renderizado)</td></tr><tr><td><code>LOW</code></td><td>Mejora incremental</td><td>Micro-optimización (como estilo de código, patrones avanzados)</td></tr></tbody></table><p><strong>Ubicación del código fuente</strong>: <code>types.ts:5</code></p>',7)])])}const h=i(o,[["render",n]]);export{f as __pageData,h as default};
